const query = $input.first().json.query || {};
const action = query.action || 'show_pin'; // show_pin, validate_pin, logout
const pin = query.pin || '';
const redirectUrl = query.redirect_url || '';
const token = query.token || '';

return [{
  json: {
    action,
    pin,
    redirect_url: redirectUrl,
    token,
    error: false
  }
}];

const params = $('Parse Parameters').first().json;
const userResult = $input.first().json;
const baseUrl = $('Webhook Login').first().json.headers?.host || 'localhost';

// Check if user was found
if (!userResult || !userResult.id) {
  return [{
    json: {
      authenticated: false,
      error_message: 'Code PIN invalide',
      redirect_url: params.redirect_url,
      show_pin: true
    }
  }];
}

const fields = userResult.fields || userResult;

// Generate session token (32 hex chars) - crypto-safe
let token;
try {
  token = globalThis.crypto.randomUUID().replace(/-/g, '');
} catch(e) {
  const a = new Uint8Array(16);
  for (let i = 0; i < 16; i++) a[i] = Math.floor(Math.random() * 256);
  token = Array.from(a, b => b.toString(16).padStart(2, '0')).join('');
}

// Token expires in 12 hours
const expiration = new Date(Date.now() + 12 * 60 * 60 * 1000).toISOString();

// Build redirect URL with token
let finalRedirect = params.redirect_url || `https://${baseUrl}/webhook/home`;
// Append token to redirect URL
const separator = finalRedirect.includes('?') ? '&' : '?';
finalRedirect = finalRedirect + separator + 'token=' + token;

return [{
  json: {
    authenticated: true,
    user_record_id: userResult.id,
    nom_complet: fields.nom_complet || fields.nom_utilisateur || 'Utilisateur',
    role: fields.role || 'couture',
    token: token,
    token_expiration: expiration,
    redirect_url: finalRedirect,
    show_pin: false
  }
}];

const data = $('Process Auth').first().json;

return [{
  json: {
    id: data.user_record_id,
    token_session: data.token,
    token_expiration: data.token_expiration,
    derniere_connexion: new Date().toISOString()
  }
}];

const params = $('Parse Parameters').first().json;
const errorMsg = $json.error_message || '';
const redirectUrl = params.redirect_url || $json.redirect_url || '';
const baseUrl = $('Webhook Login').first().json.headers?.host || 'localhost';

const loginActionUrl = `https://${baseUrl}/webhook/login`;

const html = `<!DOCTYPE html>
<html lang="fr">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no">
  <title>Connexion - MON USINE</title>
  <style>
    *{box-sizing:border-box;margin:0;padding:0}
    body{font-family:'Segoe UI',-apple-system,BlinkMacSystemFont,sans-serif;background:#f0f2f5;min-height:100vh;display:flex;justify-content:center;align-items:center;padding:15px;color:#111827}
    .login-container{width:100%;max-width:360px;text-align:center}
    .logo{font-size:2rem;font-weight:bold;color:#2563eb;margin-bottom:10px}
    .subtitle{color:#6b7280;font-size:0.9rem;margin-bottom:30px}
    .pin-display{display:flex;justify-content:center;gap:12px;margin-bottom:25px}
    .pin-dot{width:20px;height:20px;border-radius:50%;background:#e5e7eb;border:2px solid #d1d5db;transition:all 0.2s}
    .pin-dot.filled{background:#2563eb;border-color:#2563eb;box-shadow:0 0 10px rgba(37,99,235,0.3)}
    .pin-dot.error{background:#dc2626;border-color:#dc2626;box-shadow:0 0 10px rgba(220,38,38,0.3);animation:shake 0.5s}
    @keyframes shake{0%,100%{transform:translateX(0)}25%{transform:translateX(-8px)}75%{transform:translateX(8px)}}
    .error-msg{color:#dc2626;font-size:0.9rem;margin-bottom:15px;min-height:24px}
    .keypad{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:20px}
    .key{background:#ffffff;border:1px solid #e5e7eb;border-radius:16px;padding:22px;font-size:1.8rem;font-weight:600;color:#111827;cursor:pointer;-webkit-tap-highlight-color:transparent;transition:all 0.15s;user-select:none}
    .key:active{background:#eff6ff;transform:scale(0.95);border-color:#2563eb}
    .key.special{font-size:1.2rem;color:#6b7280}
    .key.special:active{background:#fef2f2;border-color:#dc2626}
    .key.empty{visibility:hidden;pointer-events:none}
    .loading{display:none;margin:20px auto}
    .loading.active{display:block}
    .spinner{width:40px;height:40px;border:3px solid #e5e7eb;border-top-color:#2563eb;border-radius:50%;animation:spin 0.8s linear infinite;margin:0 auto}
    @keyframes spin{to{transform:rotate(360deg)}}
    .user-info{display:none;background:#ecfdf5;border:1px solid #a7f3d0;border-radius:12px;padding:15px;margin-bottom:20px}
    .user-info.show{display:block}
    .user-info .name{font-size:1.2rem;font-weight:bold;color:#059669}
    .user-info .role{color:#6b7280;font-size:0.85rem;margin-top:5px}
  </style>
</head>
<body>
  <div class="login-container">
    <div class="logo">MON USINE</div>
    <div class="subtitle">Entrez votre code PIN</div>

    <div class="pin-display">
      <div class="pin-dot" id="d0"></div>
      <div class="pin-dot" id="d1"></div>
      <div class="pin-dot" id="d2"></div>
      <div class="pin-dot" id="d3"></div>
    </div>

    <div class="error-msg" id="errorMsg">${errorMsg}</div>

    <div class="loading" id="loading">
      <div class="spinner"></div>
      <p style="color:#6b7280;margin-top:10px;font-size:0.85rem">Connexion en cours...</p>
    </div>

    <div class="keypad" id="keypad">
      <div class="key" onclick="addDigit('1')">1</div>
      <div class="key" onclick="addDigit('2')">2</div>
      <div class="key" onclick="addDigit('3')">3</div>
      <div class="key" onclick="addDigit('4')">4</div>
      <div class="key" onclick="addDigit('5')">5</div>
      <div class="key" onclick="addDigit('6')">6</div>
      <div class="key" onclick="addDigit('7')">7</div>
      <div class="key" onclick="addDigit('8')">8</div>
      <div class="key" onclick="addDigit('9')">9</div>
      <div class="key empty"></div>
      <div class="key" onclick="addDigit('0')">0</div>
      <div class="key special" onclick="clearPin()">Effacer</div>
    </div>
  </div>

  <script>
    let pin = '';
    const redirectUrl = decodeURIComponent('${encodeURIComponent(redirectUrl)}');
    const loginUrl = '${loginActionUrl}';

    function addDigit(d) {
      if (pin.length >= 4) return;
      pin += d;
      updateDots();
      document.getElementById('errorMsg').textContent = '';

      if (pin.length === 4) {
        // Auto-submit after 4 digits
        setTimeout(submitPin, 200);
      }
    }

    function clearPin() {
      pin = '';
      updateDots();
      // Remove error styling
      document.querySelectorAll('.pin-dot').forEach(d => d.classList.remove('error'));
      document.getElementById('errorMsg').textContent = '';
    }

    function updateDots() {
      for (let i = 0; i < 4; i++) {
        const dot = document.getElementById('d' + i);
        dot.classList.toggle('filled', i < pin.length);
        dot.classList.remove('error');
      }
    }

    function submitPin() {
      document.getElementById('keypad').style.display = 'none';
      document.getElementById('loading').classList.add('active');

      let url = loginUrl + '?action=validate_pin&pin=' + pin;
      if (redirectUrl) {
        url += '&redirect_url=' + encodeURIComponent(redirectUrl);
      }

      window.location.href = url;
    }
  </script>
</body>
</html>`;

return [{json: {html}}];
